def parse_url(url_str):
    """Parse URL and ensure it has a scheme."""
    if not url_str.startswith(('http://', 'https://')):
        url_str = 'http://' + url_str
    return url_str


def resolve_url(base_url, href, ignore_fragments=False):
    """Resolve a relative URL against a base URL."""
    if href.startswith(('javascript:', 'mailto:', 'tel:', '#')):
        return None

    if href.startswith('//'):
        parsed = urlparse(base_url)
        href = parsed.scheme + ':' + href

    resolved = urljoin(base_url, href)

    if ignore_fragments:
        # Remove fragment
        parts = list(urlparse(resolved))
        parts[4] = ''  # fragment
        resolved = urlunparse(parts)

    return resolved


def get_real_host(url):
    """Get the host from a URL."""
    parsed = urlparse(url)
    return parsed.hostname or ''


def matches_filter(url, patterns):
    """Check if URL matches any regex pattern."""
    if not patterns:
        return True
    for pattern in patterns:
        if re.search(pattern, url):
            return True
    return False


def status_in_range(status_str, accepted_codes):
    """Check if a status code falls within accepted ranges."""
    for code_spec in accepted_codes:
        if '..' in code_spec:
            start, end = code_spec.split('..')
            if int(start) <= status_str <= int(end):
                return True
        else:
            if status_str == int(code_spec):
                return True
    return False


def check_link(url, timeout=10, headers=None, proxy=None, skip_tls=False, max_retries=0,
               rate_limiter=None, max_body_size=10000000):
    """Check a single link and return the HTTP status code or error."""
    if rate_limiter:
        rate_limiter.wait()

    retry_count = 0
    last_error = None

    while retry_count <= max_retries:
        try:
            ssl_ctx = None
            if skip_tls:
                ssl_ctx = ssl.create_default_context()
                ssl_ctx.check_hostname = False
                ssl_ctx.verify_mode = ssl.CERT_NONE

            req = Request(url)
            if headers:
                for h in headers:
                    if ':' in h:
                        key, val = h.split(':', 1)
                        req.add_header(key.strip(), val.strip())

            # Use a custom opener for proxy support
            import urllib.request
            opener = urllib.request.build_opener()
            if proxy:
                opener.add_handler(urllib.request.ProxyHandler({
                    'http': proxy,
                    'https': proxy,
                }))

            if skip_tls:
                opener.add_handler(urllib.request.HTTPSHandler(context=ssl_ctx))

            response = opener.open(req, timeout=timeout)
            status = response.getcode()
            response.close()
            return status, None

        except HTTPError as e:
            return e.code, None
        except URLError as e:
            last_error = str(e.reason)
            if max_retries > 0:
                retry_count += 1
                time.sleep(0.1)
            else:
                return None, last_error
        except Exception as e:
            last_error = str(e)
            if max_retries > 0:
                retry_count += 1
                time.sleep(0.1)
            else:
                return None, last_error

    return None, last_error


def check_link_buffered(url, timeout=10, headers=None, proxy=None, skip_tls=False, 
                        max_retries=0, rate_limiter=None, buffer_size=4096, max_body_size=10000000):
