class RateLimiter:
    """Simple rate limiter."""
    def __init__(self, rate):
        self.rate = rate
        self.lock = threading.Lock()
        self.last_time = 0

    def wait(self):
        if self.rate <= 0:
            return
        with self.lock:
            now = time.time()
            elapsed = now - self.last_time
            min_interval = 1.0 / self.rate
            if elapsed < min_interval:
                time.sleep(min_interval - elapsed)
            self.last_time = time.time()


