    print(f"checked {len(all_results)} links")

    # Separate broken and OK results
    broken = [(url, status, error) for url, status, error in all_results 
              if error or not status_in_range(status, accepted_code_parts)]
    ok = [(url, status, error) for url, status, error in all_results 
          if not error and status_in_range(status, accepted_code_parts)]

