               follow_redirects=True, max_redirections=64, buffer_size=4096,
               max_body_size=10000000, dns_resolver=None):
    """Fetch a page and return (status, body) tuple."""
    try:
        import urllib.request

        ssl_ctx = None
        if skip_tls:
            ssl_ctx = ssl.create_default_context()
            ssl_ctx.check_hostname = False
            ssl_ctx.verify_mode = ssl.CERT_NONE

        req = Request(url)
        req.add_header('User-Agent', 'Muffet')
        if headers:
            for h in headers:
                if ':' in h:
                    key, val = h.split(':', 1)
                    req.add_header(key.strip(), val.strip())

        opener = urllib.request.build_opener()
        if proxy:
            opener.add_handler(urllib.request.ProxyHandler({
                'http': proxy,
                'https': proxy,
            }))
        if skip_tls:
            opener.add_handler(urllib.request.HTTPSHandler(context=ssl_ctx))

        response = opener.open(req, timeout=timeout)
        status = response.getcode()

        body = b''
        body_bytes = 0
        while body_bytes < max_body_size:
            chunk_size = min(buffer_size, max_body_size - body_bytes)
            chunk = response.read(chunk_size)
            if not chunk:
                break
            body += chunk
            body_bytes += len(chunk)

        response.close()

        # Try to decode
        charset = 'utf-8'
        content_type = response.headers.get('Content-Type', '').lower()
        # This is complex, simplified:
        try:
            text = body.decode('utf-8', errors='replace')
        except:
            text = body.decode('latin-1', errors='replace')

        return status, text

    except HTTPError as e:
        return e.code, None
    except Exception as e:
        return None, str(e)


