def resolve_url(base_url, href, base_href=None, ignore_fragments=False):
    """Resolve a relative URL against a base URL."""
    if not href:
        return None

    href = href.strip()
    if not href:
        return None

    # Skip javascript:, mailto:, tel:, data:, and fragment-only URLs
    if href.startswith(('javascript:', 'mailto:', 'tel:', 'data:', 'git://', 'svn:')):
        return None

    if href.startswith('#'):
        return None

    # Handle // protocol-relative URLs
    if href.startswith('//'):
        parsed = urlparse(base_url)
        href = parsed.scheme + ':' + href

    # Handle base href
    if base_href:
        base_url = urljoin(base_url, base_href)

    resolved = urljoin(base_url, href)

    if ignore_fragments:
        parts = list(urlparse(resolved))
        parts[4] = ''  # Remove fragment
        resolved = urlunparse(parts)

    return resolved


def status_in_range(status, accepted_codes_str):
    """Check if a status code falls within accepted ranges."""
    for part in accepted_codes_str.split(','):
        part = part.strip()
        if '..' in part:
            start, end = part.split('..', 1)
            if int(start) <= status <= int(end):
                return True
        else:
            if status == int(part):
                return True
    return False


def matches_filters(url, exclude_patterns, include_patterns):
    """Check if URL passes the filter rules."""
    for pattern in exclude_patterns:
        if re.search(pattern, url):
            return False
    if include_patterns:
        for pattern in include_patterns:
            if re.search(pattern, url):
                return True
        return False
    return True


