            ctx = None
            if skip_tls:
                ctx = ssl.create_default_context()
                ctx.check_hostname = False
                ctx.verify_mode = ssl.CERT_NONE

            req = Request(url)
            if headers:
                for h in headers:
                    if ':' in h:
                        key, val = h.split(':', 1)
                        req.add_header(key.strip(), val.strip())

            opener = build_opener()
            if proxy:
                opener.add_handler(ProxyHandler({'http': proxy, 'https': proxy}))
            if skip_tls:
                opener.add_handler(HTTPSHandler(context=ctx))

            resp = opener.open(req, timeout=timeout)
            code = resp.getcode()
            # Drain the body
            drained = 0
            while drained < max_body_size:
                chunk = resp.read(min(buffer_size, max_body_size - drained))
                if not chunk:
                    break
                drained += len(chunk)
            resp.close()
            return code, None

        except urllib_HTTPError as e:
            return e.code, None
        except urllib_URLError as e:
            reason = str(e.reason)
            if retry < max_retries:
                retry += 1
                time.sleep(0.1)
                continue
            return None, reason
        except Exception as e:
            reason = str(e)
            if retry < max_retries:
                retry += 1
                time.sleep(0.1)
                continue
            return None, reason

    return None, "max retries exceeded"


def fetch_page(url, timeout, headers, proxy, skip_tls, buffer_size, max_body_size):
    """Fetch a page and return (status_code, body_text_or_error)."""
    try:
        ctx = None
        if skip_tls:
            ctx = ssl.create_default_context()
            ctx.check_hostname = False
            ctx.verify_mode = ssl.CERT_NONE

        req = Request(url)
        if headers:
            for h in headers:
                if ':' in h:
                    key, val = h.split(':', 1)
                    req.add_header(key.strip(), val.strip())

        opener = build_opener()
        if proxy:
            opener.add_handler(ProxyHandler({'http': proxy, 'https': proxy}))
        if skip_tls:
            opener.add_handler(HTTPSHandler(context=ctx))

        resp = opener.open(req, timeout=timeout)
        code = resp.getcode()

        body = b''
        drained = 0
        while drained < max_body_size:
            chunk = resp.read(min(buffer_size, max_body_size - drained))
            if not chunk:
                break
            body += chunk
            drained += len(chunk)
        resp.close()

        # Decode
        content_type = resp.headers.get('Content-Type', '')
        encoding = 'utf-8'
        if 'charset=' in content_type.lower():
            enc = content_type.lower().split('charset=')[-1].split(';')[0].strip()
            if enc:
                encoding = enc
        try:
            text = body.decode(encoding, errors='replace')
        except:
            try:
                text = body.decode('utf-8', errors='replace')
            except:
                text = body.decode('latin-1', errors='replace')

        return code, text
    except urllib_HTTPError as e:
        return e.code, None
    except urllib_URLError as e:
        return None, str(e.reason)
    except Exception as e:
        return None, str(e)


class RateLimiter:
    def __init__(self, rate):
        self.rate = rate
        self.semaphore = threading.Semaphore(1)
        self.last_time = [0.0]
        self.interval = 1.0 / rate if rate > 0 else 0

    def acquire(self):
        if self.rate <= 0:
            return
        with self.semaphore:
            now = time.monotonic()
            elapsed = now - self.last_time[0]
            wait = self.interval - elapsed
            if wait > 0:
                time.sleep(wait)
            self.last_time[0] = time.monotonic()


class Lock:
    """Simple lock."""
    def __init__(self):
        self._lock = threading.Lock()
    def acquire(self):
        self._lock.acquire()
    def release(self):
        self._lock.release()


