def fetched_status_in_range(status, accepted_codes_str):
    for part in accepted_codes_str.split(','):
        part = part.strip()
        if '..' in part:
            start, end = part.split('..', 1)
            if int(start) <= status <= int(end):
                return True
        else:
            if status == int(part):
                return True
    return False


