        resolved = resolve_url(page_url, href, base_href, args['ignore_fragments'])
        if resolved is None:
            continue

        # Skip external links
        link_host = get_host(resolved)
        if link_host and link_host != root_host:
            continue

        # Apply filters
        if not matches_filters(resolved, args['exclude'], args['include']):
            continue

        if args['ignore_fragments'] and '#' in resolved:
            resolved_no_frag = resolved.split('#')[0]
            if resolved_no_frag in seen:
                continue
            seen.add(resolved_no_frag)
        else:
            if resolved in seen:
                continue
            seen.add(resolved)

        # Check the link
        status, error = check_url(
            resolved,
            timeout=args['timeout'],
            headers=args['header'],
            proxy=args['proxy'],
            skip_tls=args['skip_tls_verification'],
            max_retries=args['max_retries'],
            buffer_size=args['buffer_size'],
            max_body_size=args['max_response_body_size'],
            rate_limiter=rate_limiter,
        )

        if error:
            results[page_url]["broken"].append((resolved, status, error))
        elif not status_in_range(status, args['accepted_status_codes']):
            results[page_url]["broken"].append((resolved, status, None))
        else:
