        elif arg == '--timeout=' or arg.startswith('--timeout='):
            args['timeout'] = int(arg.split('=', 1)[1])
        elif arg in ('-v', '--verbose'):
            args['verbose'] = True
        elif arg == '--proxy=' or arg.startswith('--proxy='):
            args['proxy'] = arg.split('=', 1)[1]
        elif arg == '--proxy':
            i += 1
            args['proxy'] = argv[i]
        elif arg == '--skip-tls-verification':
            args['skip_tls_verification'] = True
        elif arg == '--one-page-only':
            args['one_page_only'] = True
        elif arg == '--color=' or arg.startswith('--color='):
            args['color'] = arg.split('=', 1)[1]
        elif arg == '--color':
            i += 1
            args['color'] = argv[i]
        elif arg in ('-h', '--help'):
            args['help'] = True
        elif arg == '--version':
            args['version'] = True
        elif arg.startswith('-'):
            print(f"flag provided but not defined: {arg}", file=sys.stderr)
            sys.exit(1)
        else:
            positional.append(arg)
        i += 1

    if positional:
        args['url'] = positional[0]
        if len(positional) > 1:
            print("invalid number of arguments")
            sys.exit(1)

    return args


class HTMLLinkExtractor(HTMLParser):
    """Extracts links from HTML content."""

    def __init__(self, base_url):
        super().__init__()
        self.base_url = base_url
        self.links = []
        self.base_href = None
        self._processed_attrs = set()

    def handle_starttag(self, tag, attrs):
        attrs_dict = {}
        keyed_attrs = {}
        skip = False
        for name, value in attrs:
            key = name.lower() if name else ''
            attrs_dict[key] = value
            if value:
                keyed_attrs[key] = value

        if tag == 'base':
            if 'href' in attrs_dict and attrs_dict['href']:
                self.base_href = attrs_dict['href']
            return

        # Check for rel="nofollow" on <a> tags
        if tag == 'a' and 'rel' in attrs_dict:
            rels = [x.strip().lower() for x in attrs_dict['rel'].split() if x.strip()]
            if 'nofollow' in rels:
                return

        tag = tag.lower()

        if tag == 'a' and 'href' in attrs_dict and attrs_dict['href']:
            self.links.append(attrs_dict['href'])
        elif tag == 'img' and 'src' in attrs_dict and attrs_dict['src']:
            self.links.append(attrs_dict['src'])
        elif tag == 'link' and 'href' in attrs_dict and attrs_dict['href']:
            self.links.append(attrs_dict['href'])
        elif tag == 'script' and 'src' in attrs_dict and attrs_dict['src']:
            self.links.append(attrs_dict['src'])
        elif tag == 'form' and 'action' in attrs_dict and attrs_dict['action']:
            self.links.append(attrs_dict['action'])
        elif tag == 'iframe' and 'src' in attrs_dict and attrs_dict['src']:
            self.links.append(attrs_dict['src'])
        elif tag == 'embed' and 'src' in attrs_dict and attrs_dict['src']:
            self.links.append(attrs_dict['src'])
        elif tag == 'source' and 'src' in attrs_dict and attrs_dict['src']:
            self.links.append(attrs_dict['src'])
        elif tag == 'source' and 'srcset' in attrs_dict and attrs_dict['srcset']:
            for part in attrs_dict['srcset'].split(','):
                url_part = part.strip().split()[0] if part.strip() else ''
                if url_part:
                    self.links.append(url_part)
        elif tag == 'video':
            if 'src' in attrs_dict and attrs_dict['src']:
                self.links.append(attrs_dict['src'])
            if 'poster' in attrs_dict and attrs_dict['poster']:
                self.links.append(attrs_dict['poster'])
        elif tag == 'audio' and 'src' in attrs_dict and attrs_dict['src']:
            self.links.append(attrs_dict['src'])
        elif tag == 'area' and 'href' in attrs_dict and attrs_dict['href']:
            self.links.append(attrs_dict['href'])
        elif tag == 'object' and 'data' in attrs_dict and attrs_dict['data']:
            self.links.append(attrs_dict['data'])
        elif tag == 'input':
            if (attrs_dict.get('type', '').lower() in ('image',)) and 'src' in attrs_dict and attrs_dict['src']:
                self.links.append(attrs_dict['src'])
        elif tag == 'table' and 'background' in attrs_dict and attrs_dict['background']:
            self.links.append(attrs_dict['background'])
        elif tag == 'td' and 'background' in attrs_dict and attrs_dict['background']:
            self.links.append(attrs_dict['background'])
        elif tag == 'th' and 'background' in attrs_dict and attrs_dict['background']:
            self.links.append(attrs_dict['background'])


def resolve_url(base_url, href, base_href=None, ignore_fragments=False):
    """Resolve a relative URL against a base URL."""
    if not href:
        return None

    href = href.strip()
    if not href:
        return None

    # Skip javascript:, mailto:, tel:, data:, and fragment-only URLs
    if href.startswith(('javascript:', 'mailto:', 'tel:', 'data:', 'git://', 'svn:')):
        return None

    if href.startswith('#'):
        return None

    # Handle // protocol-relative URLs
    if href.startswith('//'):
        parsed = urlparse(base_url)
        href = parsed.scheme + ':' + href

    # Handle base href
    if base_href:
        base_url = urljoin(base_url, base_href)

    resolved = urljoin(base_url, href)

    if ignore_fragments:
        parts = list(urlparse(resolved))
        parts[4] = ''  # Remove fragment
        resolved = urlunparse(parts)

    return resolved


def status_in_range(status, accepted_codes_str):
    """Check if a status code falls within accepted ranges."""
    for part in accepted_codes_str.split(','):
        part = part.strip()
        if '..' in part:
            start, end = part.split('..', 1)
            if int(start) <= status <= int(end):
                return True
        else:
            if status == int(part):
                return True
    return False


def matches_filters(url, exclude_patterns, include_patterns):
    """Check if URL passes the filter rules."""
    for pattern in exclude_patterns:
        if re.search(pattern, url):
            return False
    if include_patterns:
        for pattern in include_patterns:
            if re.search(pattern, url):
                return True
        return False
    return True


def get_host(url):
    """Get the host from a URL."""
    try:
        return urlparse(url).hostname or ''
    except:
        return ''


def check_url(url, timeout, headers, proxy, skip_tls, max_retries, buffer_size, max_body_size, rate_limiter):
    """Check a single URL and return (status_code, error_string_or_none)."""
    if rate_limiter:
        rate_limiter.acquire()

    retry = 0
    while retry <= max_retries:
        try:
            ctx = None
            if skip_tls:
                ctx = ssl.create_default_context()
                ctx.check_hostname = False
                ctx.verify_mode = ssl.CERT_NONE

            req = Request(url)
            if headers:
                for h in headers:
                    if ':' in h:
                        key, val = h.split(':', 1)
                        req.add_header(key.strip(), val.strip())

            opener = build_opener()
            if proxy:
                opener.add_handler(ProxyHandler({'http': proxy, 'https': proxy}))
            if skip_tls:
                opener.add_handler(HTTPSHandler(context=ctx))

            resp = opener.open(req, timeout=timeout)
            code = resp.getcode()
            # Drain the body
            drained = 0
            while drained < max_body_size:
                chunk = resp.read(min(buffer_size, max_body_size - drained))
                if not chunk:
                    break
                drained += len(chunk)
            resp.close()
            return code, None

        except urllib_HTTPError as e:
            return e.code, None
        except urllib_URLError as e:
            reason = str(e.reason)
            if retry < max_retries:
                retry += 1
                time.sleep(0.1)
                continue
            return None, reason
        except Exception as e:
            reason = str(e)
            if retry < max_retries:
                retry += 1
                time.sleep(0.1)
                continue
            return None, reason

    return None, "max retries exceeded"


def fetch_page(url, timeout, headers, proxy, skip_tls, buffer_size, max_body_size):
    """Fetch a page and return (status_code, body_text_or_error)."""
    try:
        ctx = None
        if skip_tls:
            ctx = ssl.create_default_context()
            ctx.check_hostname = False
            ctx.verify_mode = ssl.CERT_NONE

        req = Request(url)
        if headers:
            for h in headers:
                if ':' in h:
                    key, val = h.split(':', 1)
                    req.add_header(key.strip(), val.strip())

        opener = build_opener()
        if proxy:
            opener.add_handler(ProxyHandler({'http': proxy, 'https': proxy}))
        if skip_tls:
            opener.add_handler(HTTPSHandler(context=ctx))

        resp = opener.open(req, timeout=timeout)
        code = resp.getcode()

        body = b''
        drained = 0
        while drained < max_body_size:
            chunk = resp.read(min(buffer_size, max_body_size - drained))
            if not chunk:
                break
            body += chunk
            drained += len(chunk)
        resp.close()

        # Decode
        content_type = resp.headers.get('Content-Type', '')
        encoding = 'utf-8'
        if 'charset=' in content_type.lower():
            enc = content_type.lower().split('charset=')[-1].split(';')[0].strip()
            if enc:
                encoding = enc
        try:
            text = body.decode(encoding, errors='replace')
        except:
            try:
                text = body.decode('utf-8', errors='replace')
            except:
                text = body.decode('latin-1', errors='replace')

        return code, text
    except urllib_HTTPError as e:
        return e.code, None
    except urllib_URLError as e:
        return None, str(e.reason)
    except Exception as e:
        return None, str(e)


class RateLimiter:
    def __init__(self, rate):
        self.rate = rate
        self.semaphore = threading.Semaphore(1)
        self.last_time = [0.0]
        self.interval = 1.0 / rate if rate > 0 else 0

    def acquire(self):
        if self.rate <= 0:
            return
        with self.semaphore:
            now = time.monotonic()
            elapsed = now - self.last_time[0]
            wait = self.interval - elapsed
            if wait > 0:
                time.sleep(wait)
            self.last_time[0] = time.monotonic()


class Lock:
    """Simple lock."""
    def __init__(self):
        self._lock = threading.Lock()
    def acquire(self):
        self._lock.acquire()
    def release(self):
        self._lock.release()


