def fetched_status_in_range(status, accepted_codes_str):
    for part in accepted_codes_str.split(','):
        part = part.strip()
        if '..' in part:
            start, end = part.split('..', 1)
            if int(start) <= status <= int(end):
                return True
        else:
            if status == int(part):
                return True
    return False


def process_links_for_page(page_url, extractor, args, root_host, rate_limiter, results, crawl_queue, visited):
    """Process links from the root page."""
    base_href = extractor.base_href

    seen = set()
    for href in extractor.links:
        resolved = resolve_url(page_url, href, base_href, args['ignore_fragments'])
        if resolved is None:
            continue

        # Skip external links
        link_host = get_host(resolved)
        if link_host and link_host != root_host:
            continue

        # Apply filters
        if not matches_filters(resolved, args['exclude'], args['include']):
            continue

        if args['ignore_fragments'] and '#' in resolved:
            resolved_no_frag = resolved.split('#')[0]
            if resolved_no_frag in seen:
                continue
            seen.add(resolved_no_frag)
        else:
            if resolved in seen:
                continue
            seen.add(resolved)

        # Check the link
        status, error = check_url(
            resolved,
            timeout=args['timeout'],
            headers=args['header'],
            proxy=args['proxy'],
            skip_tls=args['skip_tls_verification'],
            max_retries=args['max_retries'],
            buffer_size=args['buffer_size'],
            max_body_size=args['max_response_body_size'],
            rate_limiter=rate_limiter,
        )

        if error:
            results[page_url]["broken"].append((resolved, status, error))
        elif not status_in_range(status, args['accepted_status_codes']):
            results[page_url]["broken"].append((resolved, status, None))
        else:
            results[page_url]["ok"].append((resolved, status))

            # If this looks like an HTML page, add to crawl queue
            if args['ignore_fragments']:
                key = resolved.split('#')[0]
                lock = threading.Lock()
                lock.acquire()
                if key not in visited:
                    visited.add(key)
                    crawl_queue.append(key)
                lock.release()
            else:
                lock = threading.Lock()
                lock.acquire()
                if resolved not in visited:
                    visited.add(resolved)
                    crawl_queue.append(resolved)
                lock.release()


def process_links_for_recursed_page(ext, args, root_host, page_url, rate_limiter, results, crawl_queue, visited):
    """Process links from a recursively crawled page."""
    results[page_url] = {"broken": [], "ok": []}
    base_href = ext.base_href

    seen = set()
    for href in ext.links:
        resolved = resolve_url(page_url, href, base_href, args['ignore_fragments'])
        if resolved is None:
            continue

        link_host = get_host(resolved)
        if link_host and link_host != root_host:
            continue

        if not matches_filters(resolved, args['exclude'], args['include']):
            continue

        if args['ignore_fragments']:
            key = resolved.split('#')[0]
            if key in seen:
                continue
            seen.add(key)
        else:
            if resolved in seen:
                continue
            seen.add(resolved)

        status, error = check_url(
            resolved,
            timeout=args['timeout'],
            headers=args['header'],
            proxy=args['proxy'],
            skip_tls=args['skip_tls_verification'],
            max_retries=args['max_retries'],
            buffer_size=args['buffer_size'],
            max_body_size=args['max_response_body_size'],
            rate_limiter=rate_limiter,
        )

        if error:
            results[page_url]["broken"].append((resolved, status, error))
        elif not status_in_range(status, args['accepted_status_codes']):
            results[page_url]["broken"].append((resolved, status, None))
        else:
            results[page_url]["ok"].append((resolved, status))

            if args['ignore_fragments']:
                key = resolved.split('#')[0]
            else:
                key = resolved

            lock = threading.Lock()
            lock.acquire()
            if key not in visited:
                visited.add(key)
                crawl_queue.append(key)
            lock.release()


def output_json(results):
    output = []
    for page_url, page_data in results.items():
        entry = {"url": page_url, "links": []}
        for link_url, status, error in page_data.get("broken", []):
            link_entry = {"url": link_url}
            if error:
                link_entry["error"] = error
            else:
                link_entry["error"] = str(status)
            entry["links"].append(link_entry)
        output.append(entry)
    print(json.dumps(output))


def output_junit(results):
    print('<?xml version="1.0" encoding="UTF-8"?>')
    print('<testsuites>')

    for page_url, page_data in results.items():
        broken = page_data.get("broken", [])
        ok = page_data.get("ok", [])
        total = len(broken) + len(ok)
        fail = len(broken)

        print(f'  <testsuite name="{page_url}" tests="{total}" failures="{fail}" skipped="0">')
        for link_url, status in ok:
            print(f'    <testcase name="{link_url}" classname="{page_url}"></testcase>')
        for link_url, status, error in broken:
            error_msg = error if error else str(status)
            print(f'    <testcase name="{link_url}" classname="{page_url}">')
            print(f'      <failure message="{error_msg}"></failure>')
            print(f'</testcase>')
        print('  </testsuite>')

    print('</testsuites>')


def output_junit_root_only(root_url, broken):
    print('<?xml version="1.0" encoding="UTF-8"?>')
    print('<testsuites>')
    print(f'  <testsuite name="{root_url}" tests="0" failures="0" skipped="0"></testsuite>')
    print('</testsuites>')


