def resolve_url(base_url, href, base_href=None, ignore_fragments=False):
    """Resolve a relative URL against a base URL."""
    if not href:
        return None

    href = href.strip()
    if not href:
        return None

    # Skip javascript:, mailto:, tel:, data:, and fragment-only URLs
    if href.startswith(('javascript:', 'mailto:', 'tel:', 'data:', 'git://', 'svn:')):
        return None

    if href.startswith('#'):
        return None

    # Handle // protocol-relative URLs
    if href.startswith('//'):
        parsed = urlparse(base_url)
        href = parsed.scheme + ':' + href

    # Handle base href
    if base_href:
        base_url = urljoin(base_url, base_href)

    resolved = urljoin(base_url, href)

    if ignore_fragments:
        parts = list(urlparse(resolved))
        parts[4] = ''  # Remove fragment
        resolved = urlunparse(parts)

    return resolved


