        # We need to process links concurrently to produce concurrent output
        # The original Go version seems to process pages concurrently

        # Concurrent output lock
        out_lock = threading.Lock()

        # Collect broken results per page for JSON/JUnit
        page_results_lock = threading.Lock()
        page_results = {}  # page_url -> {"broken": [...], "ok": [...]}

        def print_line(line):
            with out_lock:
                print(line, flush=True)

        def process_page_links(page_url, extractor, base_href_local):
            """Process all links from a page and return crawled sub-pages."""
            results_broken = []
            results_ok = []
            crawled = []
            seen = set()

            for href in extractor.links:
                resolved = resolve_href(page_url, href, base_href_local, ignore_fragments)
                if resolved is None:
