def process_page_links_safe(page_url, extractor, base_href_local, open_args, root_host, accepted, 
                           timeout, skip_tls, max_retries, max_body_size, buf_size, 
                           excludes, includes, ignore_fragments):
    """Process all links on a page and return (broken, ok, crawled)."""
    broken = []
    ok = []
    crawled = []
    seen = set()

    for href in extractor.links:
        resolved = resolve_href(page_url, href, base_href_local, ignore_fragments)
        if resolved is None:
            continue
        if is_external(resolved, root_host):
            continue
        if not passes_filter(resolved, excludes, includes):
            continue

        if ignore_fragments:
            key = strip_frag(resolved, True)
            if key in seen:
                continue
            seen.add(key)
        else:
            if resolved in seen:
                continue
            seen.add(resolved)

        status, err = check_link(open_args, resolved, timeout, skip_tls, max_retries, max_body_size, buf_size)

        if err:
            broken.append((resolved, status, err))
        elif not check_accepted(status, accepted):
            broken.append((resolved, status, None))
        else:
            ok.append((resolved, status))

    return broken, ok, crawled


