class HTMLLinkExtractor(HTMLParser):
    def __init__(self, base_url):
        super().__init__()
        self.base_url = base_url
        self.links = []
        self.base_href = None
        self._in_nofollow = False

    def handle_starttag(self, tag, attrs):
        attrs_lower = {}
        values = {}
        for name, value in attrs:
            k = name.lower() if name else ''
            attrs_lower[k] = value
            if value is not None:
                values[k] = value

        if tag == 'base' and 'href' in values:
            self.base_href = values['href']
            return

        if tag == 'a':
            if 'rel' in attrs_lower:
                rels = [x.strip().lower() for x in attrs_lower['rel'].split() if x]
                if 'nofollow' in rels:
                    return
        if tag == 'a' and 'href' in values:
            self.links.append(values['href'])
        elif tag in ('img', 'video', 'audio', 'iframe', 'embed', 'source', 
                      'input') and 'src' in values:
            self.links.append(values['src'])
        elif tag in ('video',) and 'poster' in values:
            self.links.append(values['poster'])
        elif tag in ('link',) and 'href' in values:
            self.links.append(values['href'])
        elif tag in ('script',) and 'src' in values:
            self.links.append(values['src'])
        elif tag in ('form',) and 'action' in values:
            self.links.append(values['action'])
        elif tag in ('source',) and 'srcset' in values:
            for p in values['srcset'].split(','):
                u = p.strip().split()[0] if p.strip() else ''
                if u:
                    self.links.append(u)
        elif tag in ('video', 'object') and 'src' in values:
            self.links.append(values['src'])
        elif tag in ('video',) and 'poster' in values:
            self.links.append(values['poster'])
        elif tag in ('area',) and 'href' in values:
            self.links.append(values['href'])
        elif tag in ('object',) and 'data' in values:
            self.links.append(values['data'])


def is_external(url, root_host):
    try:
        h = urlparse(url).hostname
        return h is not None and h != root_host
    except:
        return True


def resolve_href(base_url, href, base_href=None, ignore_fragments=False):
    if not href:
        return None
    href = href.strip()
    if not href:
        return None
    lower = href.lower()
    if lower.startswith(('javascript:', 'mailto:', 'tel:', 'data:', 'git://', 'svn:')):
        return None
    if lower.startswith('#'):
        return None
    if href.startswith('//'):
        parsed = urlparse(base_url)
        href = f"{parsed.scheme}:" + href
    if base_href:
        base_url = urljoin(base_url, base_href)
    resolved = urljoin(base_url, href)
    if ignore_fragments:
        p = list(urlparse(resolved))
        p[4] = ''
        resolved = urlunparse(p)
    return resolved


def check_accepted(status, accepted_codes_str):
    for part in accepted_codes_str.split(','):
        part = part.strip()
        if '..' in part:
            lo, hi = part.split('..')
            if int(lo) <= status <= int(hi):
                return True
        else:
            if status == int(part):
                return True
    return False


def passes_filter(url, excludes, includes):
    for pat in excludes:
        if re.search(pat, url):
            return False
    if includes:
        for pat in includes:
            if re.search(pat, url):
                return True
        return False
    return True


def make_opener(headers, proxy, skip_tls):
    opener = build_opener()
    if proxy:
        opener.add_handler(ProxyHandler({'http': proxy, 'https': proxy}))
    if skip_tls:
        ctx = ssl.create_default_context()
        ctx.check_hostname = False
        ctx.verify_mode = ssl.CERT_NONE
        opener.add_handler(HTTPSHandler(context=ctx))
    return opener, headers, skip_tls


def fetch(open_args, url, timeout, max_body_size):
    opener, hdrs, skip_tls = open_args
    req = Request(url)
    req.add_header('User-Agent', 'Muffet')
    for h in hdrs:
        if ':' in h:
            k, v = h.split(':', 1)
            req.add_header(k.strip(), v.strip())
    try:
        resp = opener.open(req, timeout=timeout)
        code = resp.getcode()
        body = b''
        sz = 0
        buf = 4096
        while sz < max_body_size:
            chunk = resp.read(min(buf, max_body_size - sz))
            if not chunk:
                break
            body += chunk
            sz += len(chunk)
        resp.close()
        enc = 'utf-8'
        ct = ''
        try:
            ct = resp.headers.get('Content-Type', '')
        except:
            pass
        if 'charset=' in ct.lower():
            enc = ct.lower().split('charset=')[-1].split(';')[0].strip()
        try:
            text = body.decode(enc, errors='replace')
        except:
            text = body.decode('utf-8', errors='replace')
        return code, text
    except HTTPError as e:
        return e.code, None
    except URLError as e:
        return None, str(e.reason)
    except Exception as e:
        return None, str(e)


def check_link(open_args, url, timeout, skip_tls, max_retries, max_body_size, buf_size):
    retry = 0
    while retry <= max_retries:
        try:
            opener, hdrs, _ = open_args
            if skip_tls:
                ctx = ssl.create_default_context()
                ctx.check_hostname = False
                ctx.verify_mode = ssl.CERT_NONE
                opener.remove_handler(type(opener.handlers[-1]) if opener.handlers else None)
            req = Request(url)
            req.add_header('User-Agent', 'Muffet')
            for h in hdrs:
                if ':' in h:
                    k, v = h.split(':', 1)
                    req.add_header(k.strip(), v.strip())
            op = build_opener()
            # Just open directly for link checking
            resp = op.open(req, timeout=timeout)
            code = resp.getcode()
            sz = 0
            while sz < max_body_size:
                chunk = resp.read(min(buf_size, max_body_size - sz))
                if not chunk:
                    break
                sz += len(chunk)
            resp.close()
            return code, None
        except HTTPError as e:
            return e.code, None
        except URLError as e:
            reason = str(e.reason)
            if retry < max_retries:
                retry += 1
                continue
            return None, reason
        except Exception as e:
            reason = str(e)
            if retry < max_retries:
                retry += 1
                continue
            return None, reason
    return None, "max retries exceeded"


def strip_frag(url, ignore_fragments):
    if ignore_fragments and '#' in url:
        return url.split('#')[0]
    return url


def main():
    a = parse_args(sys.argv[1:])

