            print('[]')
        elif fmt == 'junit':
            print('<?xml version="1.0" encoding="UTF-8"?>')
            print('<testsuites>')
            print(f'  <testsuite name="{root_url}" tests="0" failures="0" skipped="0"></testsuite>')
            print('</testsuites>')
        sys.exit(0)

    # Extract links from root page
    ext = HTMLLinkExtractor(root_url)
    ext.feed(result)
    base_href = ext.base_href

    # Crawl state
    if not one_page_only:
        # Collect all pages to crawl
        pages_to_crawl = [root_url]
        visited = {root_url}

        # We need to process links concurrently to produce concurrent output
        # The original Go version seems to process pages concurrently

