    if not root_url.startswith(('http://', 'https://')):
        root_url = 'http://' + root_url

    root_host = urlparse(root_url).hostname
    if not root_host:
        print("failed to fetch root page: missing port in address")
        sys.exit(1)

    accepted = a['accepted_status_codes']
    timeout = a['timeout']
    hdrs = a['header']
    proxy = a['proxy']
    skip_tls = a['skip_tls_verification']
    max_retries = a['max_retries']
    max_body_size = a['max_response_body_size']
    buf_size = a['buffer_size']
    ignore_fragments = a['ignore_fragments']
    one_page_only = a['one_page_only']
    max_conns = a['max_connections']
    verbose = a['verbose']
    excludes = a['exclude']
    includes = a['include']

    # Fetch root
    opener, _, _ = make_opener(hdrs, proxy, skip_tls)
    open_args = (opener, hdrs, skip_tls)

    code, result = fetch(open_args, root_url, timeout, max_body_size)
    if code is None:
        print(f"failed to fetch root page: {result}")
        sys.exit(1)
    if not check_accepted(code, accepted):
        print(f"failed to fetch root page: {code}")
        sys.exit(1)

    if result is None:
        if fmt == 'json':
            print('[]')
        elif fmt == 'junit':
            print('<?xml version="1.0" encoding="UTF-8"?>')
            print('<testsuites>')
            print(f'  <testsuite name="{root_url}" tests="0" failures="0" skipped="0"></testsuite>')
            print('</testsuites>')
        sys.exit(0)

    # Extract links from root page
    ext = HTMLLinkExtractor(root_url)
    ext.feed(result)
    base_href = ext.base_href

    # Crawl state
    if not one_page_only:
        # Collect all pages to crawl
        pages_to_crawl = [root_url]
        visited = {root_url}

        # We need to process links concurrently to produce concurrent output
        # The original Go version seems to process pages concurrently

        # Concurrent output lock
        out_lock = threading.Lock()

        # Collect broken results per page for JSON/JUnit
        page_results_lock = threading.Lock()
        page_results = {}  # page_url -> {"broken": [...], "ok": [...]}

        def print_line(line):
            with out_lock:
                print(line, flush=True)

        def process_page_links(page_url, extractor, base_href_local):
            """Process all links from a page and return crawled sub-pages."""
            results_broken = []
            results_ok = []
            crawled = []
            seen = set()

            for href in extractor.links:
                resolved = resolve_href(page_url, href, base_href_local, ignore_fragments)
                if resolved is None:
                    continue
                if is_external(resolved, root_host):
                    continue
                if not passes_filter(resolved, excludes, includes):
                    continue
                key = strip_frag(resolved, ignore_fragments)
                if ignore_fragments:
                    if key in seen:
                        continue
                    seen.add(key)
                else:
                    if resolved in seen:
                        continue
                    seen.add(resolved)

                status, err = check_link(open_args, resolved, timeout, skip_tls, max_retries, max_body_size, buf_size)

                if err:
                    results_broken.append((resolved, status, err))
                elif not check_accepted(status, accepted):
                    results_broken.append((resolved, status, None))
                else:
                    results_ok.append((resolved, status))
                    if not ignore_fragments:
                        crawl_key = resolved
                    else:
                        crawl_key = key
                    if crawl_key not in visited and crawl_key != page_url and not one_page_only:
                        crawled.append(crawl_key)

