# ----------------------------------------------------------------------
# Argument parsing
# ----------------------------------------------------------------------
def read_val(argv, i):
    """Return (value, next_index) reading either '=value' or next arg."""
    if i < len(argv) and '=' in argv[i] and not argv[i].startswith('-='):
        return argv[i].split('=', 1)[1], i
    else:
        if i + 1 < len(argv):
            return argv[i + 1], i + 1
        return '', i

def parse_args(argv):
    cfg = dict(
        url=None,
        accepted_status_codes='200..300',
        buffer_size=4096, max_connections=512,
        max_connections_per_host=512,
