        exclude=[], include=[],
        follow_robots_txt=False, follow_sitemap_xml=False,
        header=[], ignore_fragments=False,
        max_retries=0, dns_resolver=None,
        fmt='text', json_old=False, verbose_json=False,
        junit_old=False, max_redirections=64,
