        one_page_only=False, color='auto',
        help=False, version=False,
    )
    pos = []
    i = 0
    while i < len(argv):
        a = argv[i]
        lt = a.lower()
        if a in ('-h', '--help'): cfg['help']=True
        elif a == '--version': cfg['version']=True
        elif a == '--accepted-status-codes' or a.startswith('--accepted-status-codes='):
            v,i = read_val(argv, i); i-=1; cfg['accepted_status_codes']=v
        elif a in ('-b','--buffer-size') or a.startswith('--buffer-size='):
            v,i = read_val(argv, i); i-=1; cfg['buffer_size']=int(v)
        elif a in ('-c','--max-connections') or a.startswith('--max-connections='):
