        elif a=='--max-connections-per-host' or a.startswith('--max-connections-per-host='):
            v,i = read_val(argv,i); i-=1; cfg['max_connections_per_host']=int(v)
        elif a=='--max-response-body-size' or a.startswith('--max-response-body-size='):
