        elif a=='--rate-limit' or a.startswith('--rate-limit='):
            v,i = read_val(argv,i); i-=1; cfg['rate_limit']=float(v)
        elif a in ('-t','--timeout') or a.startswith('--timeout='):
            v,i = read_val(argv,i); i-=1; cfg['timeout']=int(v)
        elif a in ('-v','--verbose'): cfg['verbose']=True
        elif a=='--proxy' or a.startswith('--proxy='):
            v,i = read_val(argv,i); i-=1; cfg['proxy']=v
        elif a=='--skip-tls-verification': cfg['skip_tls']=True
        elif a=='--one-page-only': cfg['one_page_only']=True
        elif a=='--color' or a.startswith('--color='):
            v,i = read_val(argv,i); i-=1; cfg['color']=v
        elif a.startswith('-'):
            print(f"flag provided but not defined: {a}", file=sys.stderr)
            sys.exit(1)
        else:
            pos.append(a)
        i += 1

    if pos:
