# ----------------------------------------------------------------------
# HTML link extractor
# ----------------------------------------------------------------------
class LinkExtractor(HTMLParser):
    def __init__(self, base):
        super().__init__()
        self.base = base
        self.links = []
        self.base_href = None

    def handle_starttag(self, tag, attrs):
        ad = {}
        for n, v in attrs:
            k = (n or '').lower()
            if k not in ad:
                ad[k] = (v or '').strip()
            k_orig = (n or '')
            if k_orig not in ad:
                ad[k_orig] = v or ''

        if tag == 'base':
            self.base_href = ad.get('href', None)
            return

        # rel=nofollow on <a>
        if tag == 'a':
            r = ad.get('rel', '')
            if 'nofollow' in r.lower().split():
                return
            if ad.get('href', None):
                self.links.append(ad['href'])
        elif tag == 'img' and ad.get('src'):
            self.links.append(ad['src'])
        elif tag == 'link' and ad.get('href'):
            self.links.append(ad['href'])
        elif tag == 'script' and ad.get('src'):
            self.links.append(ad['src'])
        elif tag == 'form' and ad.get('action'):
            self.links.append(ad['action'])
        elif tag == 'iframe' and ad.get('src'):
            self.links.append(ad['src'])
        elif tag == 'embed' and ad.get('src'):
            self.links.append(ad['src'])
        elif tag == 'source':
            if ad.get('src'):
                self.links.append(ad['src'])
            elif ad.get('srcset'):
                for p in ad['srcset'].split(','):
                    u = p.strip().split()[0]
                    if u:
                        self.links.append(u)
        elif tag == 'video':
            if ad.get('src'):
                self.links.append(ad['src'])
            if ad.get('poster'):
                self.links.append(ad['poster'])
        elif tag == 'audio' and ad.get('src'):
            self.links.append(ad['src'])
        elif tag == 'area' and ad.get('href'):
            self.links.append(ad['href'])
        elif tag == 'object' and ad.get('data'):
            self.links.append(ad['data'])
        elif tag == 'input' and ad.get('type','').lower()=='image' and ad.get('src'):
            self.links.append(ad['src'])

# ----------------------------------------------------------------------
# URL helpers
# ----------------------------------------------------------------------
_MAGIC_SCHEMES = ('://',)
_SKIP_SCHEMES = ('javascript:', 'mailto:', 'tel:', 'data:', 'git://', 'svn:')

def resolve(base, href, base_href=None, ignore_frag=False):
    if not href or not href.strip():
        return None
    href = href.strip()
    lo = href.lower()
    for ms in _SKIP_SCHEMES:
        if lo.startswith(ms):
            return None
    if lo.startswith('#'):
        return None
    if href.startswith('//'):
        p = urlparse(base)
        href = f'{p.scheme}:' + href
    if base_href:
        base = urljoin(base, base_href)
    r = urljoin(base, href)
    if ignore_frag:
        parts = list(urlparse(r))
        parts[4] = ''
        r = urlunparse(parts)
    return r

def same_host(url, host):
    try:
        return urlparse(url).hostname == host
    except:
        return False

def pas_filter(url, ex, inc):
    for p in ex:
        if p and re.search(p, url):
            return False
    if inc:
        for p in inc:
            if re.search(p, url):
                return True
        return False
    return True

def status_ok(code, codes_str):
    for part in codes_str.split(','):
        part = part.strip()
        if '..' in part:
            lo, hi = part.split('..')
            if int(lo) <= code <= int(hi):
                return True
        else:
            if code == int(part):
                return True
    return False

# Removal of fragment for matching/visited 
def frag_key(url, ignore_frag):
    if ignore_frag and '#' in url:
        return url.split('#')[0]
    return url

# ----------------------------------------------------------------------
# HTTP helpers
# ----------------------------------------------------------------------
def build_opener_obj(proxy, skip_tls):
    o = build_opener()
    if proxy:
        o.add_handler(ProxyHandler({'http': proxy, 'https': proxy}))
    if skip_tls:
        c = ssl.create_default_context()
        c.check_hostname = False
        c.verify_mode = ssl.CERT_NONE
        o.add_handler(HTTPSHandler(context=c))
    return o

def add_headers(req, hdr_list):
    for h in hdr_list:
        if ':' in h:
            k, v = h.split(':', 1)
            req.add_header(k.strip(), v.strip())

def fetch_page(opener, url, timeout, max_body, buf_sz, hdr_list):
    try:
        rq = Request(url)
        add_headers(rq, hdr_list)
        resp = opener.open(rq, timeout=timeout)
        code = resp.getcode()
        body_bytes = resp.read(max_body)
        resp.close()
        ct = ''
        try:
            ct = resp.headers.get('Content-Type', '')
        except:
            pass
        enc = 'utf-8'
        if 'charset=' in ct.lower():
            e = ct.lower().split('charset=')[-1].split(';')[0].strip()
            if e:
                enc = e
        return code, body_bytes.decode(enc, errors='replace')
    except HTTPError as e:
        return e.code, b''
    except URLError as e:
        return None, f'{e.reason}'
    except Exception as e:
        return None, str(e)

def check_link(opener, url, timeout, skip_tls, max_retry, max_body, buf_sz, hdr_list):
    attempt = 0
    while attempt <= max_retry:
        try:
            rq = Request(url)
            add_headers(rq, hdr_list)
            o = build_opener()
            if skip_tls:
                c = ssl.create_default_context()
                c.check_hostname = False
                c.verify_mode = ssl.CERT_NONE
                o.add_handler(HTTPSHandler(context=c))
            resp = o.open(rq, timeout=timeout)
            code = resp.getcode()
            sz = 0
            while sz < max_body:
                chunk = resp.read(min(buf_sz, max_body - sz))
                if not chunk:
                    break
                sz += len(chunk)
            resp.close()
            return code, None
        except HTTPError as e:
            return e.code, None
        except URLError as e:
            err = str(e.reason)
            if attempt < max_retry:
                attempt += 1
                continue
            return None, err
        except Exception as e:
            err = str(e)
            if attempt < max_retry:
                attempt += 1
                continue
            return None, err
    return None, "retries exhausted"

# ----------------------------------------------------------------------
# Core logic
# ----------------------------------------------------------------------
class Crawler:
    def __init__(self, cfg):
        self.cfg = cfg
        self.verbose = cfg['verbose'] or cfg['verbose_json']
        self.txt_fmt = cfg['fmt']
        if cfg['json_old']:
            self.txt_fmt = 'json'
        if cfg['junit_old']:
            self.txt_fmt = 'junit'
        self.out_lock = threading.Lock()
        self.print_queue = threading.Lock()

    def _put_line(self, line):
        """Thread-safe print."""
        with self.out_lock:
            print(line)

    def run(self):
        root_url = self.cfg['url']
        if not root_url.startswith(('http://', 'https://')):
            root_url = 'http://' + root_url

        root_host = urlparse(root_url).hostname
        if not root_host:
            print("failed to fetch root page: missing port in address")
            sys.exit(1)

        # Fetch root page
        opener = build_opener_obj(self.cfg['proxy'], self.cfg['skip_tls'])
        code, body = fetch_page(opener, root_url, self.cfg['timeout'],
                                self.cfg['max_response_body_size'],
                                self.cfg['buffer_size'],
                                self.cfg['header'])
        if code is None:
            print(f'failed to fetch root page: {body}')
            sys.exit(1)
        if not status_ok(code, self.cfg['accepted_status_codes']):
            print(f'failed to fetch root page: {code}')
            sys.exit(1)

        if not body:
            # empty body, nothing to check
            self._output_done([], [], [], None)
            sys.exit(0)

        # Extract links from the root page
        ext = LinkExtractor(root_url)
        ext.feed(body)
        bh = ext.base_href

        if self.cfg['one_page_only']:
            broken, ok, _ = self._process_links(root_url, ext.links, bh)
            # one page only
            if self.txt_fmt == 'json':
                self._output_json([root_url], {root_url: (broken, ok)})
            elif self.txt_fmt == 'junit':
                self._output_junit({root_url: (broken, ok)})
            else:
                self._output_text({root_url: (broken, ok)})
        else:
            # Recursive crawl
            all_results = {}  # page -> (broken_links, ok_links)
            self._crawl(root_url, opener, ext, root_host, all_results)
            if self.txt_fmt == 'json':
                self._output_json(list(all_results.keys()), all_results)
            elif self.txt_fmt == 'junit':
                self._output_junit(all_results)
            else:
                self._output_text(all_results)

        any_broken = any(b for b, _ in all_results.values()) if all_results else False
        sys.exit(1 if any_broken else 0)

    def _process_links(self, page_url, links, base_href):
        """Process links on a page. Returns (broken, ok)."""
        broken = []
        ok = []
        seen = set()
        root_host = urlparse(self.cfg['url']).hostname

        for href in links:
            resolved = resolve(page_url, href, base_href, self.cfg['ignore_fragments'])
            if resolved is None:
                continue
            if not same_host(resolved, root_host):
                continue
            if not pas_filter(resolved, self.cfg['exclude'], self.cfg['include']):
                continue

            key = frag_key(resolved, self.cfg['ignore_fragments']) if self.cfg['ignore_fragments'] else resolved
            # deduplicate
            if key in seen:
                continue
            seen.add(key)

            status, err = check_link(
                None, resolved, self.cfg['timeout'], self.cfg['skip_tls'],
                self.cfg['max_retries'], self.cfg['max_response_body_size'],
                self.cfg['buffer_size'], self.cfg['header'],
            )

            if err:
                broken.append((resolved, err))
            elif not status_ok(status, self.cfg['accepted_status_codes']):
                broken.append((resolved, str(status)))
            else:
                ok.append((resolved, status))

        return broken, ok

    def _crawl(self, root_url, opener, root_ext, root_host, all_results):
        """Recursively crawl pages, collecting link results."""
        crawl_queue = [root_url]
        visited = {root_url}

        Result = namedtuple('Result', 'page_url broken ok')
        import collections
        Result = collections.namedtuple('Result', 'page_url broken ok')

        while crawl_queue:
            batch = crawl_queue[:]
            crawl_queue = []
            new_results = []

            for page_url in batch:
                # Fetch and extract links if not root
                if page_url == root_url:
                    page_ext = root_ext
                    page_body = None
                else:
                    code2, body2 = fetch_page(opener, page_url, self.cfg['timeout'],
                                              self.cfg['max_response_body_size'],
                                              self.cfg['buffer_size'],
                                              self.cfg['header'])
                    if code2 is None or not status_ok(code2, self.cfg['accepted_status_codes']) or not body2:
                        continue
                    page_ext = LinkExtractor(page_url)
                    page_ext.feed(body2)

                bh = page_ext.base_href
                broken, ok = self._process_links(page_url, page_ext.links, bh)

                # If verbose text, print as we go
                if self.cfg['verbose'] and self.txt_fmt == 'text':
                    self._put_line(page_url)
                    for ru, s in ok:
                        self._put_line(f'\t{s}\t{ru}')
                    for ru, msg in broken:
                        self._put_line(f'\t{msg}\t{ru}')

                new_results.append(page_url)
                all_results.setdefault(page_url, (broken, ok))

                # Queue new pages to crawl
                for ru, s in ok:
                    key = frag_key(ru, self.cfg['ignore_fragments']) if self.cfg['ignore_fragments'] else ru
                    if key not in visited:
                        visited.add(key)
                        if key != page_url:
                            crawl_queue.append(key)

    def _output_text(self, all_results):
        for page_url, (broken, ok) in all_results.items():
            if self.cfg['verbose'] or broken:
                if self.cfg['verbose']:
                    self._put_line(page_url)
                if not self.cfg['verbose']:
                    self._put_line(page_url)
                for ru, msg in broken:
                    self._put_line(f'\t{msg}\t{ru}')
                if self.cfg['verbose']:
                    for ru, s in ok:
                        self._put_line(f'\t{s}\t{ru}')

    def _output_json(self, page_order, all_results):
        entries = []
        for pu in page_order:
            broken, ok = all_results.get(pu, ([], []))
            links = []
            if self.verbose:
                for ru, s in ok:
                    links.append({"url": ru, "status": s})
            for ru, msg in broken:
                links.append({"url": ru, "error": msg})
            entries.append({"url": pu, "links": links})
        # Remove empty-entries if not verbose and no links at all? Actually keep them
        # The binary shows all pages that were visited in recursive crawl
        print(json.dumps(entries))

    def _output_junit(self, all_results):
        print('<?xml version="1.0" encoding="UTF-8"?>')
        print('<testsuites>')
        for page_url, (broken, ok) in all_results.items():
            total = len(broken) + len(ok)
            fails = len(broken)
