        elif a=='--max-retries' or a.startswith('--max-retries='):
            v,i = read_val(argv, i); r['max_retries']=int(v)
        elif a=='--dns-resolver' or a.startswith('--dns-resolver='):
            v,i = read_val(argv, i); r['dns_resolver']=v
        elif a=='--format' or a.startswith('--format='):
            v,i = read_val(argv, i); r['fmt']=v
        elif a=='--json': r['json_old']=True
        elif a=='--experimental-verbose-json': r['verbose_json']=True
        elif a=='--junit': r['junit_old']=True
        elif a in ('-r','--max-redirections') or a.startswith('--max-redirections='):
            v,i = read_val(argv, i); r['max_redirections']=int(v)
        elif a=='--rate-limit' or a.startswith('--rate-limit='):
            v,i = read_val(argv, i); r['rate_limit']=float(v)
        elif a in ('-t','--timeout') or a.startswith('--timeout='):
            v,i = read_val(argv, i); r['timeout']=int(v)
        elif a in ('-v','--verbose'): r['verbose']=True
        elif a=='--proxy' or a.startswith('--proxy='):
            v,i = read_val(argv, i); r['proxy']=v
        elif a=='--skip-tls-verification': r['skip_tls']=True
        elif a=='--one-page-only': r['one_page_only']=True
        elif a=='--color' or a.startswith('--color='):
            v,i = read_val(argv, i); r['color']=v
        elif a.startswith('-'):
            print(f'flag provided but not defined: {a}', file=sys.stderr); sys.exit(1)
        else:
            pos.append(a)
        i += 1
    if pos:
        r['url'] = pos[0]
        if len(pos) > 1:
            print('invalid number of arguments'); sys.exit(1)
    return r

# ---------- HTML Link Extractor ----------
class LinkExtractor(HTMLParser):
    def __init__(self, base):
        super().__init__()
        self.base = base
        self.links = []
        self.base_href = None

    def handle_starttag(self, tag, attrs):
        ad = {}
        for n, v in attrs:
            if v is not None:
                ad[(n or '').lower()] = v

        if tag == 'base':
            self.base_href = ad.get('href')
            return
        if tag == 'a':
            if 'rel' in ad and 'nofollow' in ad['rel'].lower().split():
                return
            if 'href' in ad:
                self.links.append(ad['href'])
        elif tag == 'img' and 'src' in ad:
            self.links.append(ad['src'])
        elif tag == 'link' and 'href' in ad:
            self.links.append(ad['href'])
        elif tag == 'script' and 'src' in ad:
            self.links.append(ad['src'])
        elif tag == 'form' and 'action' in ad:
            self.links.append(ad['action'])
        elif tag == 'iframe' and 'src' in ad:
            self.links.append(ad['src'])
        elif tag == 'embed' and 'src' in ad:
            self.links.append(ad['src'])
        elif tag == 'source':
            if 'src' in ad:
                self.links.append(ad['src'])
            elif 'srcset' in ad:
                for p in ad['srcset'].split(','):
                    u = p.strip().split()[0]
                    if u: self.links.append(u)
        elif tag == 'video':
            if 'src' in ad: self.links.append(ad['src'])
            if 'poster' in ad: self.links.append(ad['poster'])
        elif tag == 'audio' and 'src' in ad:
            self.links.append(ad['src'])
        elif tag == 'area' and 'href' in ad:
            self.links.append(ad['href'])
        elif tag == 'object' and 'data' in ad:
            self.links.append(ad['data'])
        elif tag == 'input' and ad.get('type','').lower()=='image' and 'src' in ad:
            self.links.append(ad['src'])

# ---------- URL Helpers ----------
_SKIP = ('javascript:','mailto:','tel:','data:','git://','svn:')
def resolve_href(base, href, base_href=None, ignore_frag=False):
    if not href or not href.strip(): return None
    href = href.strip()
    lo = href.lower()
    for s in _SKIP:
        if lo.startswith(s): return None
    if lo.startswith('#'): return None
    if href.startswith('//'):
        p = urlparse(base); href = f'{p.scheme}:' + href
    if base_href:
        base = urljoin(base, base_href)
    r = urljoin(base, href)
    if ignore_frag:
        parts = list(urlparse(r)); parts[4] = ''
        r = urlunparse(parts)
    return r

def same_host(url, host):
    try: return urlparse(url).hostname == host
    except: return False

def passes_filters(url, exc, inc):
    for p in exc:
        if p and re.search(p, url): return False
    if inc:
        for p in inc:
            if re.search(p, url): return True
        return False
    return True

def status_ok(code, codes):
    for part in codes.split(','):
        part = part.strip()
        if '..' in part:
            lo, hi = part.split('..')
            if int(lo) <= code <= int(hi): return True
        else:
            if code == int(part): return True
    return False

def frag_key(url, ignore):
    if ignore and '#' in url: return url.split('#')[0]
    return url

# ---------- HTTP helpers ----------
def make_op(proxy, skip):
    o = build_opener()
    if proxy: o.add_handler(ProxyHandler({'http': proxy, 'https': proxy}))
    if skip:
        c = ssl.create_default_context(); c.check_hostname=False; c.verify_mode=ssl.CERT_NONE
        o.add_handler(HTTPSHandler(context=c))
    return o

def add_h(req, hl):
    for h in hl:
        if ':' in h:
            k,v = h.split(':',1); req.add_header(k.strip(), v.strip())

def fetch_page(proxy, headers, skip, timeout, max_body, buf, url):
    try:
        o = make_op(proxy, skip)
        rq = Request(url); add_h(rq, headers)
        resp = o.open(rq, timeout=timeout)
        code = resp.getcode()
        raw = resp.read(max_body)
        resp.close()
        ct = ''
        try: ct = resp.headers.get('Content-Type', '')
        except: pass
        enc = 'utf-8'
        if 'charset=' in ct.lower():
            e = ct.lower().split('charset=')[-1].split(';')[0].strip()
            if e: enc = e
        return code, raw.decode(enc, errors='replace')
    except HTTPError as e: return e.code, ''
    except URLError as e: return None, f'{e.reason}'
    except Exception as e: return None, str(e)

def check_one(proxy, headers, skip, timeout, retries, max_body, buf, url):
    attempt = 0
    while attempt <= retries:
        try:
            o = make_op(proxy, skip)
            rq = Request(url); add_h(rq, headers)
            resp = o.open(rq, timeout=timeout)
            code = resp.getcode()
            sz = 0
            while sz < max_body:
                chunk = resp.read(min(buf, max_body - sz))
                if not chunk: break
                sz += len(chunk)
            resp.close()
            return code, None
        except HTTPError as e: return e.code, None
        except URLError as e:
            err = str(e.reason)
            if attempt < retries: attempt += 1; continue
            return None, err
        except Exception as e:
            err = str(e)
            if attempt < retries: attempt += 1; continue
            return None, err
    return None, 'retries exhausted'

# ---------- Crawl & Process ----------
LinkCheckResult = namedtuple('LinkCheckResult', 'url status_or_error is_error')

def process_page_links(page_url, hrefs, base_href, root_host, cfg):
    """Given a page URL and its extracted hrefs, check all links.
    Returns (broken_list, ok_list) where each is [(url, message_or_status)].
    """
    broken, ok = [], []
    seen = set()
    for href in hrefs:
        resolved = resolve_href(page_url, href, base_href, cfg['ignore_fragments'])
        if resolved is None: continue
        if not same_host(resolved, root_host): continue
        if not passes_filters(resolved, cfg['exclude'], cfg['include']): continue

        k = resolved
        if cfg['ignore_fragments']:
            k = frag_key(resolved, True)
        if k in seen: continue
        seen.add(k)

        status, err = check_one(cfg['proxy'], cfg['header'], cfg['skip_tls'],
                                cfg['timeout'], cfg['max_retries'],
                                cfg['max_response_body_size'], cfg['buffer_size'], resolved)
        if err:
            broken.append(LinkCheckResult(resolved, err, True))
        elif not status_ok(status, cfg['accepted_status_codes']):
            broken.append(LinkCheckResult(resolved, str(status), False))
        else:
            ok.append(LinkCheckResult(resolved, status, False))
    return broken, ok

# ---------- Main ----------
def main():
    cfg = parse_args(sys.argv[1:])

    if cfg['help']:
        sys.stdout.write(HELP_TEXT)
        sys.exit(0)
    if cfg['version']:
        print(VERSION); sys.exit(0)
    if cfg['url'] is None:
        print('invalid number of arguments'); sys.exit(1)

    fmt = cfg['fmt']
    if cfg['json_old']: fmt = 'json'
    if cfg['junit_old']: fmt = 'junit'

    root = cfg['url']
    if not root.startswith(('http://','https://')):
        root = 'http://' + root

    root_host = urlparse(root).hostname
    if not root_host:
        print('failed to fetch root page: missing port in address'); sys.exit(1)

    # Ensure trailing slash on root for directory URLs
    # Check if root path is empty or '/' 
    rpath = urlparse(root).path
    if not rpath or rpath == '/':
        root = root.rstrip('/') + '/'

    # Fetch root page
    code, body = fetch_page(cfg['proxy'], cfg['header'], cfg['skip_tls'],
                            cfg['timeout'], cfg['max_response_body_size'],
                            cfg['buffer_size'], root)
    if code is None:
        print(f'failed to fetch root page: {body}'); sys.exit(1)
    if not status_ok(code, cfg['accepted_status_codes']):
        print(f'failed to fetch root page: {code}'); sys.exit(1)

    if not body:
        if fmt == 'json': print('[]')
        elif fmt == 'junit':
            print('<?xml version="1.0" encoding="UTF-8"?>')
            print('<testsuites>')
            print(f'  <testsuite name="{root}" tests="0" failures="0" skipped="0"></testsuite>')
            print('</testsuites>')
        sys.exit(0)

    # Extract links
    ext = LinkExtractor(root)
    ext.feed(body)
    bh = ext.base_href

    # Output collections
    out_lock = threading.Lock()
    page_results_lock = threading.Lock()
    all_results = {}  # page_url -> (broken, ok)

    def put_line(ln):
        with out_lock:
            print(ln)

    def crawl_recursive():
        """BFS crawl, processing pages concurrently."""
        queue = [root]
        visited = {root}
        ext_list = [(root, ext, bh)]

        while ext_list:
            batch = ext_list
            ext_list = []

            with ThreadPoolExecutor(max_workers=min(cfg['max_connections'], len(batch))) as pool:
                futs = {}
                for (pu, pext, pbh) in batch:
                    f = pool.submit(process_page_links, pu, pext.links, pbh, root_host, cfg)
                    futs[f] = pu

                new_pages = []
                for f in as_completed(futs):
                    pu = futs[f]
                    try:
                        broken, ok = f.result()
                    except Exception:
                        broken, ok = [], []

                    with page_results_lock:
                        all_results[pu] = (broken, ok)

                    if cfg['verbose'] and fmt == 'text':
                        put_line(pu)
                        for lc in ok:
                            put_line(f'\t{lc.status_or_error}\t{lc.url}')
                        for lc in broken:
                            put_line(f'\t{lc.status_or_error}\t{lc.url}')

                    # Find new pages to crawl
                    for lc in ok:
                        k = frag_key(lc.url, cfg['ignore_fragments'])
                        with page_results_lock:
                            with out_lock:
                                if k not in visited:
                                    visited.add(k)
                                    new_pages.append(k)

            # Fetch new pages
            for np_url in new_pages:
                if cfg['ignore_fragments']:
                    np_key = frag_key(np_url, True)
                else:
                    np_key = np_url
                if np_key in visited:
                    continue
                code2, body2 = fetch_page(cfg['proxy'], cfg['header'], cfg['skip_tls'],
                                          cfg['timeout'], cfg['max_response_body_size'],
                                          cfg['buffer_size'], np_url)
                if code2 is not None and status_ok(code2, cfg['accepted_status_codes']) and body2:
                    e2 = LinkExtractor(np_url)
                    e2.feed(body2)
                    ext_list.append((np_url, e2, e2.base_href))

    if cfg['one_page_only']:
        # Just check links on root page, don't crawl
        broken, ok = process_page_links(root, ext.links, bh, root_host, cfg)
        all_results[root] = (broken, ok)
    else:
        crawl_recursive()

    # Output
    any_broken = False
    if fmt == 'text':
        if not cfg['verbose']:
            for pu, (broken, ok) in all_results.items():
                if broken:
                    any_broken = True
                    put_line(pu)
                    for lc in broken:
                        put_line(f'\t{lc.status_or_error}\t{lc.url}')
    elif fmt == 'json':
        verbose_json = cfg['verbose'] or cfg['verbose_json']
        entries = []
        for pu in all_results:
            broken, ok = all_results[pu]
            links = []
            if not verbose_json:
                # json without verbose only shows broken
                any_broken_here = bool(broken)
                if not any_broken_here:
                    continue
                for lc in broken:
                    links.append({'url': lc.url, 'error': lc.status_or_error})
                entries.append({'url': pu, 'links': links})
            else:
                for lc in ok:
                    links.append({'url': lc.url, 'status': lc.status_or_error})
                for lc in broken:
                    links.append({'url': lc.url, 'error': lc.status_or_error})
                entries.append({'url': pu, 'links': links})
        print(json.dumps(entries))
    elif fmt == 'junit':
        print('<?xml version="1.0" encoding="UTF-8"?>')
        print('<testsuites>')
        for pu in all_results:
            broken, ok = all_results[pu]
            total = len(broken) + len(ok)
            fails = len(broken)
            any_broken |= bool(broken)
            print(f'  <testsuite name="{pu}" tests="{total}" failures="{fails}" skipped="0">')
            for lc in ok:
                print(f'    <testcase name="{lc.url}" classname="{pu}"></testcase>')
            for lc in broken:
                print(f'    <testcase name="{lc.url}" classname="{pu}">')
                print(f'      <failure message="{lc.status_or_error}"></failure>')
                print(f'</testcase>')
            print('  </testsuite>')
        print('</testsuites>')

    if cfg['verbose'] and fmt == 'text':
        any_broken = any(broken for broken, _ in all_results.values())

    sys.exit(1 if any_broken else 0)

if __name__ == '__main__':
    main()
