    any_broken = False
    if fmt == 'text':
        if not cfg['verbose']:
            for pu, (broken, ok) in all_results.items():
                if broken:
                    any_broken = True
                    put_line(pu)
                    for lc in broken:
                        put_line(f'\t{lc.status_or_error}\t{lc.url}')
