def main():
    cfg = parse_args(sys.argv[1:])

    if cfg['help']:
        sys.stdout.write(HELP_TEXT)
        sys.exit(0)
    if cfg['version']:
        print(VERSION); sys.exit(0)
    if cfg['url'] is None:
        print('invalid number of arguments'); sys.exit(1)

    fmt = cfg['fmt']
    if cfg['json_old']: fmt = 'json'
    if cfg['junit_old']: fmt = 'junit'

    root = cfg['url']
    if not root.startswith(('http://','https://')):
        root = 'http://' + root

    root_host = urlparse(root).hostname
    if not root_host:
        print('failed to fetch root page: missing port in address'); sys.exit(1)

    # Ensure trailing slash on root path-only URLs
    rpath = urlparse(root).path
    if not rpath or rpath == '/':
        root = root.rstrip('/') + '/'

    # Fetch root page
    code, body = fetch_page(cfg['proxy'], cfg['header'], cfg['skip_tls'],
                            cfg['timeout'], cfg['max_response_body_size'],
                            cfg['buffer_size'], root)
    if code is None:
        print(f'failed to fetch root page: {body}'); sys.exit(1)
    if not status_ok(code, cfg['accepted_status_codes']):
        print(f'failed to fetch root page: {code}'); sys.exit(1)

    if not body:
        if fmt == 'json': print('[]')
        elif fmt == 'junit':
            print('<?xml version="1.0" encoding="UTF-8"?>')
            print('<testsuites>')
            print(f'  <testsuite name="{root}" tests="0" failures="0" skipped="0"></testsuite>')
            print('</testsuites>')
        sys.exit(0)

    ext = LinkExtractor(root)
    ext.feed(body)
    bh = ext.base_href

    out_lock = threading.Lock()
    results_lock = threading.Lock()
    all_results = {}

    def put_line(ln):
        with out_lock:
            print(ln)

    def crawl_recursive():
        visited = {root}
        batch_list = [(root, ext, bh)]

        while batch_list:
            next_batch_list = []
            with ThreadPoolExecutor(max_workers=min(cfg['max_connections'], len(batch_list))) as pool:
                futs = {}
                for (pu, pext, pbh) in batch_list:
                    f = pool.submit(process_single_page, pu, pext.links, pbh, root_host, cfg)
                    futs[f] = pu

                newly_discovered = []
                for f in as_completed(futs):
                    pu = futs[f]
                    try:
                        brk, ok = f.result()
                    except:
                        brk, ok = [], []

                    with results_lock:
                        all_results[pu] = (brk, ok)

                    if cfg['verbose'] and fmt == 'text':
                        put_line(pu)
                        for lc in ok:
                            put_line(f'\t{lc.status_or_error}\t{lc.url}')
                        for lc in brk:
                            put_line(f'\t{lc.status_or_error}\t{lc.url}')

                    for lc in ok:
                        cand = frag_key(lc.url, cfg['ignore_fragments'])
                        with results_lock:
                            if cand not in visited:
                                visited.add(cand)
                                newly_discovered.append(cand)

            for nd in newly_discovered:
                c2, b2 = fetch_page(cfg['proxy'], cfg['header'], cfg['skip_tls'],
                                    cfg['timeout'], cfg['max_response_body_size'],
                                    cfg['buffer_size'], nd)
                if c2 is not None and status_ok(c2, cfg['accepted_status_codes']) and b2:
                    e2 = LinkExtractor(nd)
                    e2.feed(b2)
                    next_batch_list.append((nd, e2, e2.base_href))

            batch_list = next_batch_list

    if cfg['one_page_only']:
        broken, ok = process_single_page(root, ext.links, bh, root_host, cfg)
        all_results[root] = (broken, ok)
    else:
        crawl_recursive()

    # Output
    any_broken = False

    if fmt == 'text':
        if not cfg['verbose']:
            for pu, (broken, ok) in all_results.items():
                if broken:
                    any_broken = True
                    put_line(pu)
                    for lc in broken:
                        put_line(f'\t{lc.status_or_error}\t{lc.url}')
    elif fmt == 'json':
        verbose_json = cfg['verbose'] or cfg['verbose_json']
        entries = []
        for pu in all_results:
            brk, ok = all_results[pu]
            links = []
            if verbose_json:
                for lc in ok:
                    links.append({'url': lc.url, 'status': lc.status_or_error})
            for lc in brk:
                links.append({'url': lc.url, 'error': lc.status_or_error})
            if verbose_json:
                entries.append({'url': pu, 'links': links})
            else:
                if brk:
                    entries.append({'url': pu, 'links': links})
                    any_broken = True
        print(json.dumps(entries))
    elif fmt == 'junit':
        print('<?xml version="1.0" encoding="UTF-8"?>')
        print('<testsuites>')
        for pu in all_results:
            brk, ok = all_results[pu]
            total = len(brk) + len(ok)
            fails = len(brk)
            if brk: any_broken = True
            print(f'  <testsuite name="{pu}" tests="{total}" failures="{fails}" skipped="0">')
            for lc in ok:
                print(f'    <testcase name="{lc.url}" classname="{pu}"></testcase>')
            for lc in brk:
                print(f'    <testcase name="{lc.url}" classname="{pu}">')
                print(f'      <failure message="{lc.status_or_error}"></failure>')
                print(f'</testcase>')
            print('  </testsuite>')
        print('</testsuites>')

    if cfg['verbose'] and fmt == 'text':
        any_broken = any(brk for brk, _ in all_results.values())

    sys.exit(1 if any_broken else 0)

if __name__ == '__main__':
    main()
