from concurrent.futures import ThreadPoolExecutor, as_completed

VERSION = "2.11.1"

HELP_TEXT = open('/tmp/original_help.txt').read()

# ---------- Argument Parsing ----------
def read_val(argv, i):
    if i < len(argv) and '=' in argv[i] and len(argv[i]) > 1 and not (argv[i].startswith('-') and not argv[i].startswith('--')):
