        for lc in brk:
            out.append(f'    <testcase name="{lc.url}" classname="{pu}">')
            out.append(f'      <failure message="{lc.status_or_error}"></failure>')
            out.append(f'    </testcase>')
        out.append(f'  </testsuite>')


