def passes_filters(url, exc, inc):
    for p in exc:
        if p and re.search(p, url): return False
    if inc:
        for p in inc:
            if re.search(p, url): return True
        return False
    return True

def status_ok(code, codes):
    for part in codes.split(','):
        part = part.strip()
        if '..' in part:
            lo, hi = part.split('..')
            if int(lo) <= code <= int(hi): return True
        elif code == int(part): return True
    return False

def frag_key(url, ignore):
    if ignore and '#' in url: return url.split('#')[0]
    return url

def make_op(proxy, skip):
    o = build_opener()
    if proxy: o.add_handler(ProxyHandler({'http': proxy, 'https': proxy}))
    if skip:
        c = ssl.create_default_context(); c.check_hostname=False; c.verify_mode=ssl.CERT_NONE
        o.add_handler(HTTPSHandler(context=c))
    return o

def add_h(req, hl):
    for h in hl:
        if ':' in h: k,v = h.split(':',1); req.add_header(k.strip(), v.strip())

def fetch_page(proxy, headers, skip, timeout, max_body, buf, url):
    try:
        o = make_op(proxy, skip); rq = Request(url); add_h(rq, headers)
        resp = o.open(rq, timeout=timeout); code = resp.getcode()
        raw = resp.read(max_body); resp.close()
        ct = resp.headers.get('Content-Type','') if resp.headers else ''
        enc = 'utf-8'
        if 'charset=' in ct.lower():
            e = ct.lower().split('charset=')[-1].split(';')[0].strip()
            if e: enc = e
        return code, raw.decode(enc, errors='replace')
    except HTTPError as e: return e.code, ''
    except URLError as e: return None, str(e.reason)
    except Exception as e: return None, str(e)

def check_one(proxy, headers, skip, timeout, retries, max_body, buf, url):
    attempt = 0
    while attempt <= retries:
        try:
            o = make_op(proxy, skip); rq = Request(url); add_h(rq, headers)
            resp = o.open(rq, timeout=timeout); code = resp.getcode()
            sz = 0
            while sz < max_body:
                chunk = resp.read(min(buf, max_body - sz))
                if not chunk: break
                sz += len(chunk)
            resp.close(); return code, None
        except HTTPError as e: return e.code, None
        except URLError as e:
            err = str(e.reason)
            if attempt < retries: attempt += 1; continue
            return None, err
        except Exception as e:
            err = str(e)
            if attempt < retries: attempt += 1; continue
            return None, err
    return None, 'retries exhausted'

LCR = namedtuple('LCR', 'url status_or_error')

def process_single_page(page_url, hrefs, base_href, root_host, cfg):
    broken, ok, seen = [], [], set()
    for href in hrefs:
        resolved = resolve_href(page_url, href, base_href, cfg['ignore_fragments'])
        if resolved is None: continue
        if not same_host(resolved, root_host): continue
        if not passes_filters(resolved, cfg['exclude'], cfg['include']): continue
        k = frag_key(resolved, cfg['ignore_fragments'])
        if cfg['ignore_fragments']:
            if k in seen: continue; seen.add(k)
        else:
            if resolved in seen: continue; seen.add(resolved)
        status, err = check_one(cfg['proxy'], cfg['header'], cfg['skip_tls'],
                                cfg['timeout'], cfg['max_retries'],
                                cfg['max_response_body_size'], cfg['buffer_size'], resolved)
        if err: broken.append(LCR(resolved, err))
        elif not status_ok(status, cfg['accepted_status_codes']): broken.append(LCR(resolved, str(status)))
        else: ok.append(LCR(resolved, status))
    return broken, ok

def emit_junit(out, pu, brk, okl):
    total = len(brk) + len(okl); fails = len(brk)
    if total == 0:
        out.append(f'  <testsuite name="{pu}" tests="{total}" failures="{fails}" skipped="0"></testsuite>')
    else:
        out.append(f'  <testsuite name="{pu}" tests="{total}" failures="{fails}" skipped="0">')
        for lc in okl:
            out.append(f'    <testcase name="{lc.url}" classname="{pu}"></testcase>')
        for lc in brk:
            out.append(f'    <testcase name="{lc.url}" classname="{pu}">')
            out.append(f'      <failure message="{lc.status_or_error}"></failure>')
            out.append(f'    </testcase>')
        out.append(f'  </testsuite>')

def main():
    cfg = parse_args(sys.argv[1:])
    if cfg['help']: sys.stdout.write(HELP_TEXT); sys.exit(0)
    if cfg['version']: print(VERSION); sys.exit(0)
    if cfg['url'] is None: print('invalid number of arguments'); sys.exit(1)
    fmt = cfg['fmt']
    if cfg['json_old']: fmt = 'json'
    if cfg['junit_old']: fmt = 'junit'
    root = cfg['url']
    if not root.startswith(('http://','https://')): root = 'http://' + root
    root_host = urlparse(root).hostname
    if not root_host: print('failed to fetch root page: missing port in address'); sys.exit(1)
    rpath = urlparse(root).path
    if not rpath or rpath == '/': root = root.rstrip('/') + '/'
    code, body = fetch_page(cfg['proxy'], cfg['header'], cfg['skip_tls'],
                            cfg['timeout'], cfg['max_response_body_size'], cfg['buffer_size'], root)
    if code is None: print(f'failed to fetch root page: {body}'); sys.exit(1)
    if not status_ok(code, cfg['accepted_status_codes']): print(f'failed to fetch root page: {code}'); sys.exit(1)
    if not body:
        if fmt == 'json': print('[]')
        elif fmt == 'junit':
            print('<?xml version="1.0" encoding="UTF-8"?>'); print('<testsuites>')
            print(f'  <testsuite name="{root}" tests="0" failures="0" skipped="0"></testsuite>')
            print('</testsuites>')
        sys.exit(0)
    ext = LinkExtractor(root); ext.feed(body); bh = ext.base_href
    out_lock = threading.Lock(); results_lock = threading.Lock(); all_results = {}
    def put_line(ln):
        with out_lock: print(ln)
    def crawl_recursive():
        visited = {root}; batch_list = [(root, ext, bh)]
        while batch_list:
            next_batch = []
            with ThreadPoolExecutor(max_workers=min(cfg['max_connections'], max(1, len(batch_list)))) as pool:
                futs = {}
                for pu, pext, pbh in batch_list:
                    f = pool.submit(process_single_page, pu, pext.links, pbh, root_host, cfg)
                    futs[f] = pu
                newly = []
                for f in as_completed(futs):
                    pu = futs[f]
                    try: brk, ok = f.result()
                    except: brk, ok = [], []
                    with results_lock: all_results[pu] = (brk, ok)
                    if cfg['verbose'] and fmt == 'text':
                        put_line(pu)
                        for lc in ok: put_line(f'\t{lc.status_or_error}\t{lc.url}')
                        for lc in brk: put_line(f'\t{lc.status_or_error}\t{lc.url}')
                    for lc in ok:
                        c = frag_key(lc.url, cfg['ignore_fragments'])
                        need = False
                        with results_lock:
                            if c not in visited: visited.add(c); need = True
                        if need: newly.append(c)
            for nd in newly:
                c2, b2 = fetch_page(cfg['proxy'], cfg['header'], cfg['skip_tls'],
                                    cfg['timeout'], cfg['max_response_body_size'], cfg['buffer_size'], nd)
                if c2 is not None and status_ok(c2, cfg['accepted_status_codes']) and b2:
                    e2 = LinkExtractor(nd); e2.feed(b2); next_batch.append((nd, e2, e2.base_href))
            batch_list = next_batch
    if cfg['one_page_only']:
        broken, ok = process_single_page(root, ext.links, bh, root_host, cfg)
        all_results[root] = (broken, ok)
    else: crawl_recursive()
    any_broken = False
    if fmt == 'text':
        if not cfg['verbose']:
            for pu, (broken, ok) in all_results.items():
                if broken:
                    any_broken = True; put_line(pu)
                    for lc in broken: put_line(f'\t{lc.status_or_error}\t{lc.url}')
    elif fmt == 'json':
        vj = cfg['verbose'] or cfg['verbose_json']; entries = []
        for pu in all_results:
            brk, ok = all_results[pu]; links = []
            if vj:
                for lc in ok: links.append({'url':lc.url,'status':lc.status_or_error})
            for lc in brk: links.append({'url':lc.url,'error':lc.status_or_error})
            if vj: entries.append({'url':pu,'links':links})
            elif brk:
                entries.append({'url':pu,'links':links}); any_broken = True
        print(json.dumps(entries, separators=(',',':')))
    elif fmt == 'junit':
        jl = ['<?xml version="1.0" encoding="UTF-8"?>', '<testsuites>']
        for pu in all_results:
            brk, ok = all_results[pu]
            if brk: any_broken = True
            emit_junit(jl, pu, brk, ok)
        jl.append('</testsuites>')
        print('\n'.join(jl))
    if cfg['verbose'] and fmt == 'text': any_broken = any(b for b,_ in all_results.values())
    sys.exit(1 if any_broken else 0)

if __name__ == '__main__': main()
