            if 'rel' in ad and 'nofollow' in ad['rel'].lower().split(): return
            if 'href' in ad: self.links.append(ad['href'])
        elif tag == 'img' and 'src' in ad: self.links.append(ad['src'])
        elif tag == 'link' and 'href' in ad: self.links.append(ad['href'])
        elif tag == 'script' and 'src' in ad: self.links.append(ad['src'])
        elif tag == 'form' and 'action' in ad: self.links.append(ad['action'])
        elif tag == 'iframe' and 'src' in ad: self.links.append(ad['src'])
        elif tag == 'embed' and 'src' in ad: self.links.append(ad['src'])
        elif tag == 'source':
            if 'src' in ad: self.links.append(ad['src'])
            elif 'srcset' in ad:
                for p in ad['srcset'].split(','):
                    u = p.strip().split()[0]
