        elif tag == 'video':
            if 'src' in ad: self.links.append(ad['src'])
            if 'poster' in ad: self.links.append(ad['poster'])
        elif tag == 'audio' and 'src' in ad: self.links.append(ad['src'])
        elif tag == 'area' and 'href' in ad: self.links.append(ad['href'])
        elif tag == 'object' and 'data' in ad: self.links.append(ad['data'])
        elif tag == 'input' and ad.get('type','').lower()=='image' and 'src' in ad:
            self.links.append(ad['src'])

