                args['rate_limit'] = float(argv[i])
        elif arg in ('-t', '--timeout') or arg.startswith('--timeout='):
            if '=' in arg:
                args['timeout'] = int(arg.split('=', 1)[1])
            else:
                i += 1
                args['timeout'] = int(argv[i])
        elif arg in ('-v', '--verbose'):
            args['verbose'] = True
        elif arg == '--proxy' or arg.startswith('--proxy='):
            if '=' in arg:
                args['proxy'] = arg.split('=', 1)[1]
            else:
                i += 1
                args['proxy'] = argv[i]
        elif arg == '--skip-tls-verification':
            args['skip_tls_verification'] = True
        elif arg == '--one-page-only':
            args['one_page_only'] = True
        elif arg == '--color' or arg.startswith('--color='):
            if '=' in arg:
                args['color'] = arg.split('=', 1)[1]
            else:
                i += 1
                args['color'] = argv[i]
        elif arg.startswith('-'):
            print(f"flag provided but not defined: {arg}", file=sys.stderr)
            sys.exit(1)
        else:
            positional.append(arg)

        i += 1

    if len(positional) == 0:
        args['url'] = None
    elif len(positional) == 1:
        args['url'] = positional[0]
    else:
        print("invalid number of arguments")
        sys.exit(1)

    return args


def parse_accepted_codes(code_str):
    """Parse accepted status codes string like '200..300,403'."""
    accepted = []
    for part in code_str.split(','):
        part = part.strip()
        if '..' in part:
            low, high = part.split('..')
            for code in range(int(low), int(high) + 1):
                accepted.append(code)
        else:
            accepted.append(int(part))
    return set(accepted)


class LinkExtractor(HTMLParser):
    """Extract all links from HTML content."""

    def __init__(self, base_url):
        super().__init__()
        self.base_url = base_url
        self.links = []
        self.base_href = None

    def handle_starttag(self, tag, attrs):
        attrs_dict = {k.lower(): v for k, v in attrs if k is not None}

        if tag == 'base':
            if 'href' in attrs_dict:
                self.base_href = attrs_dict['href']

        if tag == 'a':
            if 'rel' in attrs_dict:
                rel_attrs = set(r.lower().strip() for r in attrs_dict['rel'].split())
                if 'nofollow' in rel_attrs:
                    return
            if 'href' in attrs_dict:
                href = attrs_dict['href'].strip()
                if href and not href.startswith('javascript:'):
                    self.links.append(href)

        elif tag in ('img', 'track'):
            if 'src' in attrs_dict:
                src = attrs_dict['src'].strip()
                if src:
                    self.links.append(src)

        elif tag == 'link':
            if 'href' in attrs_dict:
                href = attrs_dict['href'].strip()
                if href:
                    self.links.append(href)

        elif tag == 'script':
            if 'src' in attrs_dict:
                src = attrs_dict['src'].strip()
                if src:
                    self.links.append(src)

        elif tag == 'form':
            if 'action' in attrs_dict:
                action = attrs_dict['action'].strip()
                if action:
                    self.links.append(action)

        elif tag == 'iframe':
            if 'src' in attrs_dict:
                src = attrs_dict['src'].strip()
                if src:
                    self.links.append(src)

        elif tag == 'embed':
            if 'src' in attrs_dict:
                src = attrs_dict['src'].strip()
                if src:
                    self.links.append(src)

        elif tag == 'area':
            if 'href' in attrs_dict:
                href = attrs_dict['href'].strip()
                if href:
                    self.links.append(href)

        elif tag == 'video':
            if 'src' in attrs_dict:
                src = attrs_dict['src'].strip()
                if src:
                    self.links.append(src)
            if 'poster' in attrs_dict:
                poster = attrs_dict['poster'].strip()
                if poster:
                    self.links.append(poster)

        elif tag == 'audio':
            if 'src' in attrs_dict:
                src = attrs_dict['src'].strip()
                if src:
                    self.links.append(src)

        elif tag == 'source':
            if 'src' in attrs_dict:
                src = attrs_dict['src'].strip()
                if src:
                    self.links.append(src)
            elif 'srcset' in attrs_dict:
                for p in attrs_dict['srcset'].split(','):
                    url = p.strip().split(' ')[0] if p.strip() else ''
                    if url:
                        self.links.append(url)

    def get_links(self):
        return self.links

    def get_base_href(self):
        return self.base_href


def resolve_url(base_url, href, base_href=None):
    """Resolve a relative URL to an absolute URL."""
    if href.startswith(('javascript:', 'data:', 'mailto:', 'tel:', '#')):
        return None

    # Handle protocol-relative URLs
    if href.startswith('//'):
        parsed = urllib.parse.urlparse(base_url)
        href = f"{parsed.scheme}:" + href

    # If we have a base href from <base> tag
    if base_href:
        if href.startswith('//'):
            # Protocol-relative keeps original
            pass
        elif href.startswith(('http://', 'https://')):
            # Absolute URL, ignore base
            return urllib.parse.urlunparse(urllib.parse.urlparse(href))
        else:
            # Combine base_url with base_href first
            base_url = urllib.parse.urljoin(base_url, base_href)

    # Resolve the URL
    resolved = urllib.parse.urljoin(base_url, href)
    return resolved


def is_same_host(url1, url2):
    """Check if two URLs are from the same host."""
    try:
        p1 = urllib.parse.urlparse(url1)
        p2 = urllib.parse.urlparse(url2)
        return p1.hostname == p2.hostname and p1.scheme == p2.scheme
    except:
        return False


def request_url(url, timeout=10, proxy=None, skip_tls=False, headers=None, max_size=10000000):
    """Make an HTTP request and return (status_code, body) tuple."""
    try:
        req = urllib.request.Request(url)

        # Add custom headers
        if headers:
            for h in headers:
                if ':' in h:
                    key, value = h.split(':', 1)
                    req.add_header(key.strip(), value.strip())

        # Create opener with proxy support
        opener = urllib.request.build_opener()
        if proxy:
            opener.add_handler(urllib.request.ProxyHandler({'http': proxy, 'https': proxy}))

        if skip_tls:
            context = ssl._create_unverified_context()
            opener.add_handler(urllib.request.HTTPSHandler(context=context))

        response = opener.open(req, timeout=timeout)
        status = response.getcode()

        # Read body up to max_size
        body = b''
        while len(body) < max_size:
            chunk = response.read(min(4096, max_size - len(body)))
            if not chunk:
                break
            body += chunk
        response.close()

        return status, body.decode('utf-8', errors='replace')

    except urllib.error.HTTPError as e:
        return e.code, ''
    except urllib.error.URLError as e:
        raise e
    except Exception as e:
        raise e


def check_link(url, args, visited_pages, results, lock):
    """Check a single link and store the result."""
    try:
        status, body = request_url(
            url,
            timeout=args['timeout'],
            proxy=args['proxy'],
            skip_tls=args['skip_tls_verification'],
            headers=args['header'],
            max_size=args['max_response_body_size'],
        )

        accepted = parse_accepted_codes(args['accepted_status_codes'])

        if status in accepted:
            with lock:
                results['ok'].append((url, status))

            # If not one-page-only, recursively check links on this page
            if not args['one_page_only'] and status == 200:
                with lock:
                    if url in visited_pages:
                        return
                    visited_pages.add(url)

                # Extract links from the page
                base_href = None
                if '<base' in body.lower():
                    m = re.search(r'<base[^>]*href\s*=\s*["\']([^"\']*)["\']', body, re.IGNORECASE)
                    if m:
                        base_href = m.group(1)

                if body:
                    try:
                        extractor = LinkExtractor(url)
                        extractor.feed(body)
                        links = extractor.get_links()
                    except:
                        links = []
                else:
                    links = []

                for href in links:
                    resolved = resolve_url(url, href, base_href)
                    if resolved is None:
                        continue

                    # Only follow same-host links
                    if not is_same_host(args['url'], resolved):
                        continue

                    with lock:
                        if resolved in [l[0] for l in results['ok'] + results['broken'] + results['skipped']]:
                            continue

                    check_link(resolved, args, visited_pages, results, lock)

        else:
            with lock:
                results['broken'].append((url, status))

    except Exception as e:
        with lock:
            results['broken'].append((url, str(e)))


def main():
    args = parse_args()

    if args['help']:
        print(HELP_TEXT, end='')
        sys.exit(0)

    if args['version']:
        print(VERSION)
        sys.exit(0)

    if args['url'] is None:
        print("invalid number of arguments")
        sys.exit(1)

    # Determine output format
    out_format = args['format']
    if args['json']:
        out_format = 'json'
    if args['junit']:
        out_format = 'junit'

    url = args['url']

    # Ensure URL has scheme
    if not url.startswith(('http://', 'https://')):
        url = 'http://' + url

    try:
        status, body = request_url(
            url,
            timeout=args['timeout'],
            proxy=args['proxy'],
            skip_tls=args['skip_tls_verification'],
            headers=args['header'],
            max_size=args['max_response_body_size'],
        )
    except Exception as e:
        error_msg = str(e.reason) if hasattr(e, 'reason') else str(e)
        print(f"failed to fetch root page: {error_msg}")
        sys.exit(1)

    accepted = parse_accepted_codes(args['accepted_status_codes'])
    if status not in accepted:
        print(f"failed to fetch root page: {status}")
        sys.exit(1)

    # Extract links from root page
    base_href = None
    if '<base' in body.lower():
        m = re.search(r'<base[^>]*href\s*=\s*["\']([^"\']*)["\']', body, re.IGNORECASE)
        if m:
            base_href = m.group(1)

    try:
        extractor = LinkExtractor(url)
        extractor.feed(body)
        links = extractor.get_links()
    except:
        links = []

    # Apply exclude/include filters
    exclude_patterns = args['exclude']
    include_patterns = args['include']

    filtered_links = []
    for href in links:
        resolved = resolve_url(url, href, base_href)
        if resolved is None:
            continue

        # Skip external links
        if not is_same_host(url, resolved):
            continue

        link_str = resolved
        if args['ignore_fragments']:
            link_str = link_str.split('#')[0]

        # Apply exclude filters
        excluded = False
        for pattern in exclude_patterns:
            if re.search(pattern, link_str):
                excluded = True
                break
        if excluded:
            continue

        # Apply include filters
        if include_patterns:
            included = False
            for pattern in include_patterns:
                if re.search(pattern, link_str):
                    included = True
                    break
            if not included:
                continue

        filtered_links.append(resolved)

    # Check links
    visited_pages = set()
    visited_pages.add(url)

    results = {
        'ok': [],
        'broken': [],
        'skipped': [],
    }
    lock = threading.Lock()

    if args['one_page_only']:
        # Only check direct links from the root page
        for link in filtered_links:
            try:
                status, _ = request_url(
                    link,
                    timeout=args['timeout'],
                    proxy=args['proxy'],
                    skip_tls=args['skip_tls_verification'],
                    headers=args['header'],
                    max_size=args['max_response_body_size'],
                )
                if status in accepted:
                    results['ok'].append((link, status))
                else:
                    results['broken'].append((link, status))
            except Exception as e:
                results['broken'].append((link, str(e)))
    else:
        # Recursively check all links
        threads = []
        for link in filtered_links:
            t = threading.Thread(
                target=check_link,
                args=(link, args, visited_pages, results, lock)
            )
            threads.append(t)
            t.start()

        for t in threads:
            t.join()

    # Output results
    if out_format == 'json':
        output_json(results, verbose=args['verbose'] or args['experimental_verbose_json'])
    elif out_format == 'junit':
        output_junit(results, url)
    else:
        output_text(results, verbose=args['verbose'])

    # Exit with non-zero if there are broken links
    if results['broken']:
        sys.exit(1)
    else:
        sys.exit(0)


def output_text(results, verbose=False):
    """Output results in text format."""
    if verbose:
        for url, status in results['ok']:
            print(f"\t{status}\t{url}")
    for url, error in sorted(results['broken']):
        print(f"\t{error}\t{url}")


def output_json(results, verbose=False):
    """Output results in JSON format."""
    output = []

    if verbose:
        for url, status in results['ok']:
            output.append({
                "url": url,
                "status": status,
            })

    for url, error in results['broken']:
        output.append({
            "url": url,
            "error": str(error),
        })

    print(json.dumps(output, separators=(',', ':')))


def output_junit(results, base_url):
    """Output results in JUnit XML format."""
    print('<?xml version="1.0" encoding="UTF-8"?>')
    print(f'  <testsuite name="{base_url}" tests="{len(results["ok"]) + len(results["broken"])}" failures="{len(results["broken"])}" skipped="0">')
    for url, error in results['broken']:
        print(f'    <testcase name="{url}" classname="{base_url}">')
        print(f'      <failure message="{error}"></failure>')
        print(f'    </testcase>')
    print('  </testsuite>')


if __name__ == '__main__':
    main()
