                                    cfg['timeout'], cfg['max_response_body_size'],
                                    cfg['buffer_size'], nd)
                if c2 is not None and status_ok(c2, cfg['accepted_status_codes']) and b2:
                    e2 = LinkExtractor(nd)
                    e2.feed(b2)
